import { Component, OnInit, Output } from '@angular/core';

@Component({
  selector: 'app-home',
  template: require('./home.component.html'),
  styles: [require('./home.component.styl')]
})
export class HomeComponent implements OnInit {
  @Output() CustomOption: {};

  constructor() { }

  ngOnInit() {
    this.CustomOption = {
      pagetitle: 'home',
      multiple: true
    }
  }

}



